pragma solidity ^0.8.0;

contract SavingsGoal {
    address public owner;
    uint256 public fundingGoal;
    uint256 public deadline;
    mapping(address => uint256) public contributions;
    uint256 public totalRaised;

    event Contribution(address indexed contributor, uint256 amount);
    event OwnerWithdrawal(address indexed owner, uint256 amount);
    event Refund(address indexed contributor, uint256 amount);

    // Reentrancy guard
    modifier noReentrancy() {
        require(!isContract(msg.sender), "No reentrancy");
        _;
    }

    constructor(uint256 _fundingGoal, uint256 _deadline) {
        owner = msg.sender;
        fundingGoal = _fundingGoal;
        deadline = block.timestamp + _deadline;
    }

    function contribute() external payable {
        require(block.timestamp < deadline, "Deadline passed");
        require(msg.value > 0, "Contribution must be greater than 0");

        uint256 newBalance = contributions[msg.sender] + msg.value;
        contributions[msg.sender] = newBalance;
        totalRaised += msg.value;

        emit Contribution(msg.sender, msg.value);
    }

    function withdraw() external noReentrancy {
        require(block.timestamp >= deadline, "Deadline not yet reached.");
        require(totalRaised >= fundingGoal || msg.sender != owner, "Only owner can withdraw if goal is met.");

        uint256 amount = address(this).balance;
        bool success = payable(owner).transfer(amount);

        require(success, "Transfer failed");

        emit OwnerWithdrawal(owner, amount);
    }

    function refund() external {
        require(block.timestamp > deadline, "Deadline not yet reached.");
        require(totalRaised < fundingGoal, "Refunds only if goal is not met.");

        uint256 amount = contributions[msg.sender];
        contributions[msg.sender] = 0;
        payable(msg.sender).transfer(amount);
        emit Refund(msg.sender, amount);
    }

    function getTotalRaised() external view returns (uint256) {
        return totalRaised;
    }

    function getFundingGoal() external view returns (uint256) {
        return fundingGoal;
    }

    function getDeadline() external view returns (uint256) {
        return deadline;
    }

    function getContributorAmount(address contributor) external view returns (uint256) {
        return contributions[contributor];
    }

    // Helper function to check if the caller is a contract
    function isContract(address addr) internal view returns (bool) {
        uint size;
        assembly { size := extcodesize(addr) }
        return size > 0;
    }
}
```

